import java.lang.reflect.Proxy;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withSingleValue() throws IOException {
        String result = csvFormat.format("value1");
        assertEquals("value1", result);
    }

    @Test
    void testFormat_withMultipleValues() throws IOException {
        String result = csvFormat.format("value1", "value2", "value3");
        assertEquals("value1,value2,value3", result);
    }

    @Test
    void testFormat_withNullValue() throws IOException {
        String result = csvFormat.format("value1", null, "value3");
        assertEquals("value1,,value3", result);
    }

    @Test
    void testFormat_withEmptyValues() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Create a dynamic proxy for CSVPrinter that throws IOException on printRecord
        CSVPrinter proxyCsvPrinter = (CSVPrinter) Proxy.newProxyInstance(
                CSVPrinter.class.getClassLoader(),
                new Class<?>[]{CSVPrinter.class, AutoCloseable.class},
                new InvocationHandler() {
                    @Override
                    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                        if ("printRecord".equals(method.getName())) {
                            throw new IOException("IO error");
                        } else if ("close".equals(method.getName())) {
                            // no-op for close
                            return null;
                        }
                        // For all other methods, delegate to default if possible or do nothing
                        if (method.getReturnType().isPrimitive()) {
                            if (method.getReturnType() == boolean.class) {
                                return false;
                            } else if (method.getReturnType() == void.class) {
                                return null;
                            } else if (method.getReturnType() == int.class) {
                                return 0;
                            } else if (method.getReturnType() == long.class) {
                                return 0L;
                            } else if (method.getReturnType() == short.class) {
                                return (short) 0;
                            } else if (method.getReturnType() == byte.class) {
                                return (byte) 0;
                            } else if (method.getReturnType() == char.class) {
                                return '\0';
                            } else if (method.getReturnType() == float.class) {
                                return 0f;
                            } else if (method.getReturnType() == double.class) {
                                return 0d;
                            }
                        }
                        return null;
                    }
                });

        // Use reflection to create a subclass of CSVFormat that overrides print(...) method to return proxyCsvPrinter
        CSVFormat spyFormat = new CSVFormat(
                csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                new Object[]{},
                new String[]{},
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter()
        ) {
            @Override
            public CSVPrinter print(final Appendable out) throws IOException {
                return proxyCsvPrinter;
            }
        };

        IllegalStateException exception = assertThrows(IllegalStateException.class, () -> {
            spyFormat.format("value1");
        });
        assertTrue(exception.getCause() instanceof IOException);
        assertEquals("IO error", exception.getCause().getMessage());
    }
}
